gql:
query UserCounts($startDate: BigInt, $endDate: BigInt, $first: Int, $skip: Int) {
  accounts(
    first: $first
    skip: $skip
    where: { firstSeenAt_gte: $startDate, firstSeenAt_lte: $endDate }
    orderBy: "firstSeenAt"
    orderDirection: "asc"
  ) {
    id
    chain
    address
    firstSeenAt
  }
}
